type URLPreviewRequest struct {
	URL string `json:"url" validate:"required"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest

	// Bind and validate the request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: "URL is required",
		})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create context with timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request
	httpReq, err := http.NewRequestWithContext(ctxWithTimeout, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: fmt.Sprintf("Invalid URL: %v", err),
		})
	}

	// Set User-Agent to avoid being blocked by some websites
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{
			Error: fmt.Sprintf("URL returned status code: %d", resp.StatusCode),
		})
	}

	// Read the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{
			Error: fmt.Sprintf("Failed to read response body: %v", err),
		})
	}

	// Parse HTML and extract title and description
	title, description := parseHTML(string(body))

	// Return the response
	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

func parseHTML(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}

			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						nameAttr = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}

				// Check for description meta tags
				if description == "" && (nameAttr == "description" || nameAttr == "og:description") {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

