		"fe80::/10",       // IPv6 Link-local
		"::1/128",         // IPv6 loopback
		"100.64.0.0/10",   // Carrier-grade NAT
	}

	for _, block := range privateBlocks {
		_, subnet, err := net.ParseCIDR(block)
		if err != nil {
			continue
		}
		if subnet.Contains(ip) {
			return true
		}
	}

	return false
}

