package main

import (
	"context"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

type URLPreviewRequest struct {
	URL string `json:"url" validate:"required"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

type ErrorResponse struct {
	Error string `json:"error"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "URL is required"})
	}

	// Create HTTP client with 3 seconds timeout
	httpCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(httpCtx, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "Invalid URL"})
	}

	// Set a user agent to avoid being blocked by some websites
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "Failed to fetch URL, status code: " + resp.Status})
	}

	// Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, ErrorResponse{Error: "Failed to parse HTML"})
	}

	title, description := extractMetadata(doc)

	response := URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	return ctx.JSON(http.StatusOK, response)
}

func extractMetadata(n *html.Node) (title, description string) {
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			} else if n.Data == "meta" {
				var name, content, property string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						property = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if description == "" {
					if name == "description" || property == "og:description" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(n)
	return
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

