// validateURLForSSRF checks if the URL is attempting to access internal resources
func validateURLForSSRF(parsedURL *url.URL) error {
	host := parsedURL.Hostname()

	// Block localhost variations
	if isLocalhost(host) {
		return fmt.Errorf("access to localhost is not allowed")
	}

	// Resolve the hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	// Check each resolved IP
	for _, ip := range ips {
		if isPrivateOrReservedIP(ip) {
			return fmt.Errorf("access to private or reserved IP addresses is not allowed")
		}
	}

	return nil
}

// isLocalhost checks if the host is localhost
func isLocalhost(host string) bool {
	host = strings.ToLower(host)
	return host == "localhost" || 
		host == "127.0.0.1" || 
		host == "::1" || 
		host == "0.0.0.0" ||
		strings.HasPrefix(host, "127.") ||
		host == "[::1]" ||
		host == "[::]"
}

// isPrivateOrReservedIP checks if an IP is private, loopback, or reserved
func isPrivateOrReservedIP(ip net.IP) bool {
	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for private addresses
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for multicast
	if ip.IsMulticast() {
		return true
	}

	// Additional checks for reserved ranges
	if ip.To4() != nil {
		// Check for 0.0.0.0/8
		if ip[0] == 0 {
			return true
		}
		// Check for 169.254.0.0/16 (link-local)
		if ip[0] == 169 && ip[1] == 254 {
			return true
		}
		// Check for 192.0.0.0/24 (IETF Protocol Assignments)
		if ip[0] == 192 && ip[1] == 0 && ip[2] == 0 {
			return true
		}
		// Check for 192.0.2.0/24 (TEST-NET-1)
		if ip[0] == 192 && ip[1] == 0 && ip[2] == 2 {
