package main

import (
	"context"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
	"golang.org/x/net/html"
)

type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "Invalid request body",
		})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "URL is required",
		})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create context with timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request
	httpReq, err := http.NewRequestWithContext(ctxWithTimeout, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{
			Error: "Invalid URL",
		})
	}

	// Set User-Agent to avoid being blocked
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: "Failed to fetch URL: HTTP status " + resp.Status,
		})
	}

	// Parse HTML
	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{
			Error: "Failed to parse HTML: " + err.Error(),
		})
	}

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTML(body io.Reader) (string, string, error) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", "", err
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			} else if n.Data == "meta" {
				var name, content, property string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						property = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}

				if description == "" && content != "" {
					if name == "description" || property == "og:description" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

